sql:
SELECT COUNT(homeowner_id) AS number_of_consenting_homeowners
FROM homeowners
WHERE consent = 'yes';

SELECT COUNT(homeowner_id) AS total_homeowners_with_consent
FROM homeowners
WHERE consent = 'yes';

SELECT summary_date, food_growing_percent, compost_percent
FROM responses_summary
WHERE summary_date = '2023-10-02' AND demographic_id = 0;

SELECT property_type, COUNT(*) as homeowner_count
FROM homeowners
GROUP BY property_type;

SELECT contact_info
FROM homeowners
WHERE consent = 'yes';

external_knowledge:
- 'consenting homeowners' refers to those who have given consent for data usage and sharing; 
- 'flood insurance coverage percentage' is calculated as the percentage of homeowners in each group who have flood insurance; 
- 'frequent fan usage percentage' is calculated as the percentage of homeowners in each group who use fans often; 
- 'food waste composting percentage' is calculated as the percentage of homeowners in each group who compost food waste.
